// src/components/BookPage.jsx
// Responsive single-page renderer — scales text/emoji with page dimensions.

export default function BookPage({ page, pageNum, total, onShowRef, pageW, pageH }) {
  const isCover = page.type === "cover";
  const isEnd   = page.type === "end";

  // Responsive scale factor based on page dimensions
  const scale = Math.min(pageW / 380, pageH / 500, 1.6);
  const em    = (base) => Math.round(base * scale);

  return (
    <div style={{
      width:"100%", height:"100%",
      background: page.bg || "#fff",
      color: page.textColor || "#333",
      display:"flex", flexDirection:"column",
      alignItems:"center", justifyContent:"center",
      padding:`${em(24)}px ${em(20)}px`,
      boxSizing:"border-box",
      fontFamily:"'Bubblegum Sans', cursive",
      position:"relative", overflow:"hidden",
      userSelect:"none",
    }}>
      {/* decorative blobs */}
      <div style={{
        position:"absolute", top: em(-45), left: em(-45),
        width: em(140), height: em(140),
        borderRadius:"50%", background:"rgba(255,255,255,0.13)", pointerEvents:"none",
      }}/>
      <div style={{
        position:"absolute", bottom: em(-30), right: em(-30),
        width: em(100), height: em(100),
        borderRadius:"50%", background:"rgba(255,255,255,0.10)", pointerEvents:"none",
      }}/>

      {/* main emoji */}
      <div style={{ fontSize: em(isCover || isEnd ? 88 : 68), lineHeight:1, marginBottom: em(10) }}>
        {page.image}
      </div>

      {/* title */}
      <div style={{
        fontSize: em(page.titleSize || (isCover || isEnd ? (page.fontSize || 32) : 24)),
        fontWeight:800, textAlign:"center", lineHeight:1.2,
        marginBottom: em(8),
        textShadow:"0 2px 10px rgba(0,0,0,0.18)",
        letterSpacing: isCover ? "0.04em" : "0.01em",
      }}>
        {page.title}
      </div>

      {/* subtitle */}
      {(isCover || isEnd) && page.subtitle && (
        <div style={{
          fontSize: em(17), opacity:0.92, textAlign:"center",
          marginBottom: em(14), fontStyle:"italic",
        }}>
          {page.subtitle}
        </div>
      )}

      {/* body text */}
      {page.text && (
        <div style={{
          fontSize: em(page.fontSize || 17),
          textAlign:"center", lineHeight:1.75,
          maxWidth: em(320), marginTop: em(8),
          background:"rgba(255,255,255,0.28)",
          borderRadius: em(18), padding:`${em(14)}px ${em(18)}px`,
          backdropFilter:"blur(4px)",
        }}>
          {page.text}
        </div>
      )}

      {/* accent emoji */}
      {page.emoji && (
        <div style={{ fontSize: em(46), marginTop: em(16) }}>{page.emoji}</div>
      )}

      {/* 🔍 Learn button */}
      {page.reference && onShowRef && (
        <button onClick={onShowRef} style={{
          position:"absolute", top: em(10), left: em(10),
          background:"rgba(255,255,255,0.28)",
          border:"1px solid rgba(255,255,255,0.55)",
          borderRadius: em(20), padding:`${em(4)}px ${em(10)}px`,
          cursor:"pointer", fontSize: em(12), fontWeight:700,
          fontFamily:"'Nunito',sans-serif",
          color: page.textColor || "#333",
          backdropFilter:"blur(4px)",
          display:"flex", alignItems:"center", gap: em(4),
          transition:"all 0.2s",
          boxShadow:"0 2px 8px rgba(0,0,0,0.1)",
        }}>
          🔍 Learn
        </button>
      )}

      {/* page number */}
      {!isCover && (
        <div style={{
          position:"absolute", bottom: em(10),
          fontSize: em(12), opacity:0.55,
          fontFamily:"'Nunito', sans-serif",
        }}>
          {pageNum} / {total}
        </div>
      )}

      {/* stars accent */}
      {(isCover || isEnd) && (
        <div style={{
          position:"absolute", top: em(10), right: em(10),
          fontSize: em(22), opacity:0.75, letterSpacing: em(4),
        }}>⭐🌟⭐</div>
      )}
    </div>
  );
}
